#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Enemies;
using MVZ2.GameContent.Seeds;
using MVZ2Logic.Blueprints;
using PVZEngine;
using PVZEngine.Level;

namespace MVZ2.GameContent.Stages
{
    public class IZombieEndless2Behaviour : IZombieEndlessBaseBehaviour
    {
        public IZombieEndless2Behaviour(StageDefinition stageDef) : base(stageDef)
        {
        }
        protected override IEnumerable<IZELayoutItem> GetNormalLayouts()
        {
            // A类阵
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeComposite2, 1.2f); // 综合
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeControl2, 1.2f); // 控制
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeSpectral, 0.8f); // 光灵（有1火药桶）

            // B类阵
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeSpikes2, 0.4f); // 倾斜
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeDispensers2, 0.4f); // 发射器（有2火药桶）
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeInstakill2, 0.4f); // 即死
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeFire2, 0.4f); // 火焰
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeAwards, 0.2f); // 恢复
        }
        protected override IEnumerable<IZELayoutItem> GetAwardLayouts()
        {
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeAwards);
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeError, 0.2f);
            yield return new IZELayoutItem(VanillaIZombieLayoutID.izeGunpowder, 0.2f);
        }
        protected override NamespaceID GetFirstLayoutID()
        {
            return VanillaIZombieLayoutID.izeComposite2;
        }
        protected override IEnumerable<NamespaceID> GetBlueprints()
        {
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.imp);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.leatherCappedZombie);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.skeletonStatue);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.hacker);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.ironHelmettedZombie);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.cannoneerZombie);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.shadowCell);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.zombieCat);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.zombieCloud);
            yield return LogicBlueprintID.FromEntity(VanillaEnemyID.popCaptain);
        }
    }
}
